class Registration {
    constructor() {
        $(() => {
            this.registrationForm = new Form('main-form');
            this.bindEvents();
        });
    }

    bindEvents() {
        $('#confirm-registration').click(() => {
            this.registrationForm.validate();
        });

        $('.company-toggler').click(() => {
            let companyBox = $('.company-box');
            $('#IsCompany').prop('checked') ? companyBox.slideDown(300) : companyBox.slideUp(300);
        });
    }

    validateEmail(value) {
        let result = true;
        $.ajax({
            type: "POST",
            url: "/default/customer/check-email/",
            data: { Email: value },
            success: function(data) {
                if (data == 1) {
                    result = false;
                } else {
                    result = true;
                }
            },
            async: false
        });
        return result;
    }
}